ambiguous_dsl.choice_dsl:
PREFIX : <http://ambrosia.example.org/hospitality#>
PREFIX p: <http://ambrosia.example.org/hospitality/prop#>
PREFIX xsd: <http://www.w3.org/2001/XMLSchema#>
CHOICE vague {
  full: { SELECT ?executive_chef ?sous_chef WHERE {
  ?restaurants a :Restaurants .
  ?restaurants p:executive_chef ?executive_chef .
  ?restaurants p:sous_chef ?sous_chef .
} }
  component: { SELECT ?executive_chef WHERE {
  ?restaurants a :Restaurants .
  ?restaurants p:executive_chef ?executive_chef .
} }
  component_2: { SELECT ?sous_chef WHERE {
  ?restaurants a :Restaurants .
  ?restaurants p:sous_chef ?sous_chef .
} }
}

PREFIX : <http://ambrosia.example.org/hospitality#>
PREFIX p: <http://ambrosia.example.org/hospitality/prop#>
PREFIX xsd: <http://www.w3.org/2001/XMLSchema#>
CHOICE vague {
  full: { SELECT ?executive_chef ?sous_chef WHERE {
  ?r a :Restaurants .
  ?m a :MenuItems .
  ?r p:executive_chef ?executive_chef .
  ?r p:sous_chef ?sous_chef .
  ?m p:hasRestaurants ?r .
  ?m p:item_name ?item_name_f .
  FILTER(STR(?item_name_f) = "Steak")
} }
  component: { SELECT ?sous_chef WHERE {
  ?r a :Restaurants .
  ?m a :MenuItems .
  ?r p:sous_chef ?sous_chef .
  ?m p:hasRestaurants ?r .
  ?m p:item_name ?item_name_f .
  FILTER(STR(?item_name_f) = "Steak")
} }
  component_2: { SELECT ?executive_chef WHERE {
  ?r a :Restaurants .
  ?m a :MenuItems .
  ?r p:executive_chef ?executive_chef .
  ?m p:hasRestaurants ?r .
  ?m p:item_name ?item_name_f .
  FILTER(STR(?item_name_f) = "Steak")
} }
}
